            out.write("					    data : data,\r\n");
            out.write("					    success : function(result){\r\n");
            out.write("					    	\r\n");
            out.write("					    	//console.log(\"성공 여부\" + result);					    	\r\n");
            out.write("							if(result != 'success'){\r\n");
