            out.write("						var passwordValue = $(this).val();\r\n");
            out.write("					  	var passwordRegex = /^(?=.*[A-Za-z])(?=.*\\d)(?=.*[$@$!%*#?&])[A-Za-z\\d$@$!%*#?&]{8,}$/;\r\n");
            out.write("					  	\r\n");
            out.write("					  	if (!passwordRegex.test(passwordValue)) {\r\n");
            out.write("					  		$('#passwordErrorMsg').text('영문, 숫자, 특수문자를 포함하여 최소8자리 이상으로 입력해야 합니다.');\r\n");
            out.write("					  	} else {\r\n");
